definition.script:
node {
  stage('Checkout') {
    git url: '@GIT_URL@', branch: '@GIT_BRANCH@'
  }
  stage('Setup Build Tools') {
    sh 'mvn --version'
    sh 'node --version'
    sh 'npm --version'
  }
  stage('Frontend Type Check') {
    dir('ai-igris-ui') {
      sh 'npm ci'
      sh 'npx tsc --noEmit'
    }
  }
  stage('Initialize Kafka') {
    sh '''
      sg docker -c "docker compose up -d kafka"
      echo "Waiting for Kafka..."
      for i in $(seq 1 30); do
        if echo > /dev/tcp/kafka/29092 2>/dev/null; then
          echo "Kafka is ready!"
          exit 0
        fi
        echo "Waiting... ($i/30)"
        sleep 2
      done
      echo "Kafka failed to start"
      sg docker -c "docker compose logs kafka"
      exit 1
    '''
  }
  stage('Build and Test') {
    sh 'mvn -B clean verify'
  }
  stage('Cleanup') {
    sh 'sg docker -c "docker compose down -v" || true'
  }
}
